import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{a as i,i as a,n as o,o as s,r as c,s as l,t as u}from"./chunks/javap.CpTN0-Ru.js";const d=JSON.parse(`{"title":"Tipps und Tricks für VS Code","description":"Nützliche Tipps und Tricks, umd eine Arbeit zu erleichtern.","frontmatter":{"title":"Tipps und Tricks für VS Code","description":"Nützliche Tipps und Tricks, umd eine Arbeit zu erleichtern.","authors":["dicedpixels"],"prev":{"text":"Quellcode in VS Code generieren","link":"./generating-sources"},"next":false,"files":[]},"headers":[],"relativePath":"de_de/develop/getting-started/vscode/tips-and-tricks.md","filePath":"translated/de_de/develop/getting-started/vscode/tips-and-tricks.md","lastUpdated":1774101324000}`);var f={name:`de_de/develop/getting-started/vscode/tips-and-tricks.md`};function p(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Tipps und Tricks für VS Code <a class="header-anchor" href="#h1" aria-label="Permalink to “Tipps und Tricks für VS Code”">​</a></h1><p>Es ist wichtig zu lernen, wie man die generierten Quellen durchläuft, damit man Debuggen und ein Verständnis für die inneren Abläufe von Minecraft entwickeln kann. Hier beschreiben wir einige gängige Anwendungen der Entwicklungsumgebung.</p><h2 id="searching-for-a-minecraft-class" tabindex="-1">Nach einer Minecraft-Klasse suchen <a class="header-anchor" href="#searching-for-a-minecraft-class" aria-label="Permalink to “Nach einer Minecraft-Klasse suchen”">​</a></h2><p>Sobald die Quellen generiert sind, sollte es möglich sein, Minecraft-Klassen zu suchen oder anzusehen.</p><h3 id="viewing-class-definitions" tabindex="-1">Klassendefinition ansehen <a class="header-anchor" href="#viewing-class-definitions" aria-label="Permalink to “Klassendefinition ansehen”">​</a></h3><p><strong>Schnellöffnung</strong> (<kbd>Ctrl</kbd>+<kbd>P</kbd>): Schreibe <code>#</code> gefolgt von dem Namen einer Klasse (z.B. <code>#Identifier</code>).</p><p><img src="/assets/develop/getting-started/vscode/quick-open.png" alt="Schnellöffnung" loading="lazy"></p><p><strong>Zur Definition gehen</strong> (<kbd>F12</kbd>): Navigiere im Quellcode zu einer Klassendefinition, indem du bei gedrückter <kbd>Strg</kbd> -Taste auf den Namen klickst oder mit der rechten Maustaste darauf klickst und &quot;Go to Definition&quot; auswählst.</p><p><img src="/assets/develop/getting-started/vscode/go-to-definition.png" alt="Zur Definition gehen" loading="lazy"></p><h3 id="finding-references" tabindex="-1">Referenzen finden <a class="header-anchor" href="#finding-references" aria-label="Permalink to “Referenzen finden”">​</a></h3><p>Du kannst alle Verwendungen einer Klasse finden, indem du mit der rechten Maustaste auf einen Klassennamen und dann auf <strong>Find All References</strong> klickst.</p><p><img src="/assets/develop/getting-started/vscode/find-all-references.png" alt="Alle Referenzen finden" loading="lazy"></p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Wenn die oben genannten Funktionen nicht wie erwartet funktionieren, ist der Quellcode vermutlich nicht richtig angehängt. Dies lässt sich in der Regel durch Bereinigen des Arbeitsbereich-Caches beheben.</p><ul><li>Klicke auf die Schaltfläche <strong>Show Java Status Menu</strong> in der Statusleiste.</li></ul><p><img src="/assets/develop/getting-started/vscode/java-ready.png" alt="Java Status anzeigen" loading="lazy"></p><ul><li>Klicke im gerade geöffneten Menü auf <strong>Clean Workspace Cache...</strong> und bestätige den Vorgang.</li></ul><p><img src="/assets/develop/getting-started/vscode/clear-workspace.png" alt="Workspace leeren" loading="lazy"></p><ul><li>Schließe und öffne das Projekt erneut.</li></ul></div><h2 id="viewing-bytecode" tabindex="-1">Bytecode ansehen <a class="header-anchor" href="#viewing-bytecode" aria-label="Permalink to “Bytecode ansehen”">​</a></h2><p>Das Anzeigen von Bytecode ist beim Schreiben von Mixins erforderlich. Allerdings fehlt Visual Studio Code die native Unterstützung für die Anzeige von Bytecode, und die wenigen Erweiterungen, die diese hinzufügen, funktionieren möglicherweise nicht.</p><p>In diesem Fall kannst du den in Java integrierten Befehl <code>javap</code> verwenden, um den Bytecode anzuzeigen.</p><ul><li><p><strong>Suche den Pfad zu der Minecraft JAR:</strong></p><p>Öffne die Explorer-Ansicht und erweitere den Abschnitt <strong>Java-Projekte</strong>. Erweitere den Knoten <strong>Reference Libraries</strong> in der Projektstruktur und suche eine JAR-Datei, deren Name <code>minecraft-</code> enthält. Klicken mit der rechten Maustaste auf die JAR-Datei und kopiere den vollständigen Pfad.</p><p>Es könnte etwa wie folgt aussehen:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:/project/.gradle/loom-cache/minecraftMaven/net/minecraft/minecraft-merged-503b555a3d/1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2/minecraft-merged-503b555a3d-1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2.jar</span></span></code></pre></div></li></ul><p><img src="/assets/develop/getting-started/vscode/copy-path.png" alt="Pfad kopieren" loading="lazy"></p><ul><li><p><strong><code>javap</code> ausführen:</strong></p><p>Du kannst dann <code>javap</code> ausführen, indem du den oben genannten Pfad als <code>cp</code> (Klassenpfad) und den vollqualifizierten Klassennamen als letztes Argument angibst.</p><div class="language-sh line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">javap</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> C:/project/.gradle/loom-cache/minecraftMaven/net/minecraft/minecraft-merged-503b555a3d/1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2/minecraft-merged-503b555a3d-1.21.8-net.fabricmc.yarn.1_21_8.1.21.8+build.1-v2.jar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -private</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> net.minecraft.util.Identifier</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Dies wird den Bytecode in deine Terminalausgabe ausgegeben.</p></li></ul><p><img src="/assets/develop/getting-started/vscode/javap.png" alt="javap" loading="lazy"></p>`,20)]])}var m=r(f,[[`render`,p]]);export{d as __pageData,m as default};